// Lee el catalogo desde businessConfig enviado por el Router
// (el Router ya cargo los productos via /internal/tenant/by-instance)
const data = $('Recibir Datos del Router').first().json;
const catalog = data.businessConfig?.catalog || [];
if (catalog.length > 0) {
  return catalog.map(p => ({ json: p }));
}
return [{ json: { name: 'Sin productos configurados', description: '', price: 0 } }];

// Sub-workflow: Ventas
var input = $("Recibir Datos del Router").first().json;

// Productos del backend
var productosBackend = [];
try {
  var pNode = $('Buscar Productos Backend').first().json;
  if (pNode && pNode.products && Array.isArray(pNode.products)) productosBackend = pNode.products;
} catch(e) {}

var catalogoEstatico = Array.isArray(input.catalog) ? input.catalog : [];

var catalogText = '';
if (productosBackend.length > 0) {
  catalogText = 'CATALOGO (habla SOLO de estos productos):\n';
  productosBackend.forEach(function(p) {
    catalogText += '- ' + p.name;
    if (p.category) catalogText += ' [' + p.category + ']';
    if (p.price) catalogText += ' $' + Number(p.price).toLocaleString('es-CO');
    if (p.comparePrice && p.comparePrice > p.price) catalogText += ' (antes $' + Number(p.comparePrice).toLocaleString('es-CO') + ')';
    if (p.sku) catalogText += ' SKU:' + p.sku;
    if (p.description) catalogText += ' | ' + p.description;
    if (!p.available) catalogText += ' [NO DISPONIBLE]';
    if (p.stock !== null && p.stock !== undefined && p.stock <= 5) catalogText += ' [Ultimas ' + p.stock + ' unidades]';
    catalogText += '\n';
  });
} else if (catalogoEstatico.length > 0) {
  catalogText = 'CATALOGO (habla SOLO de estos productos):\n';
  catalogoEstatico.forEach(function(item) {
    catalogText += '- ' + item.name;
    if (item.price) catalogText += ' $' + Number(item.price).toLocaleString('es-CO');
    if (item.category) catalogText += ' (' + item.category + ')';
    if (item.description) catalogText += ': ' + item.description;
    if (!item.available) catalogText += ' [NO DISPONIBLE]';
    catalogText += '\n';
  });
} else {
  catalogText = 'No hay productos en el catalogo por el momento.';
}

var faqText = '';
var faqItems = Array.isArray(input.faq) ? input.faq : [];
faqText = faqItems.length > 0
  ? faqItems.map(function(f) { return 'P: ' + f.question + '\nR: ' + f.answer; }).join('\n\n')
  : 'Sin preguntas frecuentes.';

var allowedText = Array.isArray(input.allowedActions) && input.allowedActions.length > 0
  ? input.allowedActions.map(function(a) { return '- ' + a; }).join('\n')
  : '- Informar sobre productos y precios\n- Tomar pedidos';

var restrictText = Array.isArray(input.restrictions) && input.restrictions.length > 0
  ? input.restrictions.map(function(r) { return '- ' + r; }).join('\n')
  : '- No revelar informacion confidencial';

// Negocio
var businessConfig = (input.businessConfig) || {};
var addressParts = [];
var ba = businessConfig.businessAddress || {};
if (ba.street) addressParts.push(ba.street);
if (ba.city) addressParts.push(ba.city);
if (ba.state) addressParts.push(ba.state);
if (ba.reference) addressParts.push('Ref: ' + ba.reference);
var locationText = addressParts.length > 0
  ? addressParts.join(', ')
  : (input.location || businessConfig.location || '');

// Ventas config
var salesConfig = businessConfig.salesConfig || {};
var requireCustomerName = salesConfig.requireCustomerName === true;
var requireCustomerAddress = salesConfig.requireCustomerAddress === true;
var requireCustomerId = salesConfig.requireCustomerId === true;
var deliveryFee = salesConfig.deliveryFee || 0;
var deliveryType = salesConfig.deliveryType || 'both';
var confirmationInstructions = salesConfig.confirmationInstructions || '';

// Pago
var paymentConfig = businessConfig.paymentConfig || {};
var hasQrImage = !!(paymentConfig.qrImageUrl);
var paymentMethodsText = Array.isArray(input.paymentMethods) && input.paymentMethods.length > 0
  ? input.paymentMethods.join(', ')
  : '';

// ─── DATOS OBLIGATORIOS DEL CLIENTE ────────────────────────────────────────
var requiredFields = [];
if (requireCustomerName) requiredFields.push('Nombre completo');
if (requireCustomerId) requiredFields.push('Numero de cedula o documento de identidad');
if (requireCustomerAddress) requiredFields.push('Direccion completa de entrega: calle/carrera + barrio + ciudad + referencia (TODO en un campo)');

var dataRulesText = '';
if (requiredFields.length > 0) {
  dataRulesText += '\n\n=== DATOS OBLIGATORIOS DEL CLIENTE (maxima prioridad) ===\n';
  dataRulesText += 'Antes de confirmar el pedido, debes tener EXACTAMENTE estos datos:\n';
  requiredFields.forEach(function(f, i) { dataRulesText += (i+1) + '. ' + f + '\n'; });
  dataRulesText += '\nREGLAS ESTRICTAS:\n';
  dataRulesText += '- Pide SOLO los ' + requiredFields.length + ' datos de la lista anterior + la talla/variante del producto si aplica.\n';
  dataRulesText += '- NO pidas "ciudad de entrega" por separado (ya esta incluida en la direccion completa).\n';
  dataRulesText += '- NO pidas "metodo de pago" si el cliente ya lo menciono o si el negocio tiene metodo definido.\n';
  dataRulesText += '- NO confirmes el pedido hasta tener los ' + requiredFields.length + ' datos.\n';
  dataRulesText += '- NO inventes ni asumas datos del cliente.\n';
  if (confirmationInstructions) {
    dataRulesText += '\nGuia de comportamiento del negocio (NO es una lista de campos adicionales, son instrucciones de estilo):\n';
    // Extract only the style/behavior parts, ignoring field lists
    dataRulesText += confirmationInstructions + '\n';
  }
}

// Entregas
var deliveryText = '';
if (deliveryFee > 0) deliveryText += '\nCosto de domicilio: $' + Number(deliveryFee).toLocaleString('es-CO') + '\n';
if (deliveryType === 'pickup') deliveryText += 'Solo recogida en tienda.\n';
else if (deliveryType === 'delivery') deliveryText += 'Solo domicilio.\n';

// Datos bancarios
var paymentBankText = '';
if (paymentConfig.accountNumber || hasQrImage) {
  paymentBankText = '\n\nDATOS BANCARIOS PARA TRANSFERENCIA:\n';
  if (paymentConfig.bankName) paymentBankText += '- Banco: ' + paymentConfig.bankName + '\n';
  if (paymentConfig.accountNumber) {
    var tipo = paymentConfig.accountType === 'checking' ? 'Corriente' : 'Ahorros';
    paymentBankText += '- Cuenta ' + tipo + ': ' + paymentConfig.accountNumber + '\n';
  }
  if (paymentConfig.accountHolder) paymentBankText += '- Titular: ' + paymentConfig.accountHolder + '\n';
  if (hasQrImage) paymentBankText += '- QR disponible (se envia automaticamente al cliente)\n';
}

// QR: trigger amplio — cualquier mención de pago/transferencia
var qrInstructionText = '';
if (hasQrImage) {
  qrInstructionText = '\n\n=== ENVIO AUTOMATICO DEL QR DE PAGO ===\n';
  qrInstructionText += 'Cuando el cliente mencione O pregunte sobre: transferencia, Nequi, Bancolombia, QR, pago, consignar, pagar, metodo de pago —\n';
  qrInstructionText += 'DEBES escribir [ENVIAR_QR] como PRIMERA linea de tu respuesta (antes de cualquier texto).\n';
  qrInstructionText += 'Formato correcto:\n[ENVIAR_QR]\nTu respuesta normal aqui...\n';
  qrInstructionText += 'El sistema enviara automaticamente la imagen QR al cliente.\n';
}

// Confirmacion de venta
// {{ y }} → { y } en el prompt (escape LangChain template)
var confirmationTagText = '';
if (paymentConfig.confirmationMethod === 'manual' || !paymentConfig.confirmationMethod) {
  confirmationTagText = '\n\n=== CUANDO EL CLIENTE CONFIRME EL PAGO ===\n';
  confirmationTagText += 'Cuando el cliente envie comprobante, foto de transferencia, o diga que ya pago,\n';
  confirmationTagText += 'escribe en la PRIMERA linea:\n';
  confirmationTagText += '[VENTA_CONFIRMADA]{{"clientName":"<nombre>","clientId":"<cedula>","clientAddress":"<direccion>","productName":"<producto>","productDetails":"<detalle: talla, color>","quantity":1,"totalAmount":null,"paymentMessage":"<descripcion del pago>"}}\n';
  confirmationTagText += 'Luego la respuesta de confirmacion al cliente.\n';
  confirmationTagText += 'IMPORTANTE: JSON valido, comillas dobles, null para numeros desconocidos.';
}

var systemMessage =
  (input.aiInstructions || 'Eres un asistente de ventas profesional y amable.') +
  '\n\nCliente en esta conversacion: ' + (input.pushName || 'Cliente') +

  dataRulesText +

  '\n\n' + catalogText +
  '\n\nFAQ:\n' + faqText +
  (paymentMethodsText ? '\n\nMETODOS DE PAGO: ' + paymentMethodsText : '') +
  (locationText ? '\n\nUBICACION: ' + locationText : '') +
  deliveryText +
  paymentBankText +
  qrInstructionText +
  confirmationTagText +

  '\n\nACCIONES PERMITIDAS:\n' + allowedText +
  '\n\nRESTRICCIONES:\n' + restrictText +
  '\n\nMENSAJE DEL CLIENTE: "' + (input.message || '') + '"';

return [{
  json: {
    phone: input.phone,
    tenantId: input.tenantId,
    instanceName: input.instanceName,
    pushName: input.pushName,
    message: input.message,
    intent: input.intent,
    confidence: input.confidence,
    evolutionApiUrl: input.evolutionApiUrl,
    evolutionApiKey: input.evolutionApiKey,
    tenantEmail: input.tenantEmail || '',
    businessName: (businessConfig.businessName) || '',
    paymentQrImageUrl: (paymentConfig.qrImageUrl) || '',
    systemMessage: systemMessage
  }
}];

const input = $('Preparar Contexto Ventas').first().json;
const aiOutput = $input.first().json;
let response = aiOutput.output || aiOutput.text || 'Lo siento, no pude procesar tu consulta de ventas.';

// Detectar [ENVIAR_QR] tag — el sistema enviara la imagen QR al cliente
const sendQrImage = response.includes('[ENVIAR_QR]') && !!(input.paymentQrImageUrl);
if (response.includes('[ENVIAR_QR]')) {
  response = response.replace('[ENVIAR_QR]', '').trim();
}

// Detectar confirmacion de venta y parsear JSON estructurado
const saleConfirmed = response.trimStart().startsWith('[VENTA_CONFIRMADA]');
let saleData = {};
if (saleConfirmed) {
  const withoutTag = response.replace('[VENTA_CONFIRMADA]', '').trim();
  const jsonMatch = withoutTag.match(/^(\{[\s\S]*?\})(\s*[\s\S]*)$/);
  if (jsonMatch) {
    try {
      saleData = JSON.parse(jsonMatch[1]);
    } catch(e) {
      // JSON invalido — continuar sin datos estructurados
    }
    response = jsonMatch[2].trim();
  } else {
    response = withoutTag;
  }
}

let imagenProductoUrl = null;
try {
  const specificProds = $('Buscar Producto Especifico').first().json.products || [];
  if (specificProds.length > 0 && specificProds[0].imageUrl) {
    imagenProductoUrl = specificProds[0].imageUrl;
  }
} catch(e) {}

if (!imagenProductoUrl) {
  try {
    const allProds = $('Buscar Productos Backend').first().json.products || [];
    const responseLower = response.toLowerCase();
    const matched = allProds.find(p =>
      p.imageUrl && p.name &&
      (responseLower.includes(p.name.toLowerCase()) ||
       p.name.toLowerCase().split(' ').some(w => w.length > 3 && responseLower.includes(w)))
    );
    if (matched) imagenProductoUrl = matched.imageUrl;
  } catch(e) {}
}

return [{ json: {
  response, saleConfirmed, sendQrImage,
  saleData,
  imagenProductoUrl,
  intent: saleConfirmed ? 'sale_confirmed' : 'ventas',
  tokensEstimated: Math.ceil(((input.message||'') + response).length / 4),
  phone: input.phone,
  tenantId: input.tenantId,
  tenantEmail: input.tenantEmail || '',
  businessName: input.businessName || '',
  paymentQrImageUrl: input.paymentQrImageUrl || '',
  instanceName: input.instanceName,
  evolutionApiUrl: input.evolutionApiUrl || '',
  evolutionApiKey: input.evolutionApiKey || '',
  intent_handled: saleConfirmed ? 'sale_confirmed' : 'ventas',
  action_taken: saleConfirmed ? 'venta_confirmada' : 'respuesta_generada',
  metadata: { pushName: input.pushName, original_message: input.message }
} }];

const input = $('Recibir Datos del Router').first().json;
const prodData = $('Buscar Productos Backend').first().json;
const prods = (prodData.products || input.catalog || []).slice(0, 15);
const catalogText = prods.length > 0
  ? prods.map(p => {
      let line = '• ' + p.name;
      if (p.category) line += ' [' + p.category + ']';
      if (p.price) line += ' — $' + Number(p.price).toLocaleString('es-CO');
      if (p.description) line += ': ' + String(p.description).substring(0, 80);
      if (p.available === false) line += ' [NO DISPONIBLE]';
      return line;
    }).join('\n')
  : 'Sin catálogo configurado.';
const businessName = input.businessName || 'nuestra tienda';
const clientName = input.pushName || 'cliente';
const caption = input.message && input.message !== '[imagen]' ? `El cliente escribió: "${input.message}". ` : '';
const thumbnail = input.imageThumbnailBase64 || '';
const systemContent = `Eres un experto en ventas de ${businessName}. Analiza la imagen y responde SOLO en JSON con este formato exacto: {"producto_catalogo": "nombre exacto del producto si coincide con el catálogo o null si no hay coincidencia", "respuesta": "respuesta cálida y comercial en español"}`;
const userContent = [];
if (thumbnail) {
  userContent.push({ type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' + thumbnail, detail: 'low' } });
}
userContent.push({ type: 'text', text: `${caption}Catálogo disponible:\n${catalogText}\n\nIdentifica si el producto de la imagen coincide con alguno del catálogo y elabora una respuesta comercial.` });
const openAiBody = {
  model: 'gpt-4o',
  response_format: { type: 'json_object' },
  messages: [{ role: 'system', content: systemContent }, { role: 'user', content: userContent }],
  max_tokens: 500
};
return [{ json: { openAiBody, prods, phone: input.phone, tenantId: input.tenantId, instanceName: input.instanceName, pushName: input.pushName, evolutionApiUrl: input.evolutionApiUrl || '', evolutionApiKey: input.evolutionApiKey || '' } }];

const ctx = $('Preparar Request Imagen').first().json;
const apiResp = $input.first().json;
let responseText, productoCatalogo = null;
try {
  const raw = apiResp.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(raw);
  responseText = parsed.respuesta || raw;
  productoCatalogo = parsed.producto_catalogo || null;
} catch(e) {
  responseText = apiResp.choices?.[0]?.message?.content || '¡Hola! Recibí tu imagen. ¿Qué producto buscas?';
}
let imagenProductoUrl = null;
if (productoCatalogo && ctx.prods && ctx.prods.length > 0) {
  const lc = productoCatalogo.toLowerCase().trim();
  const match = ctx.prods.find(p => p.name && (p.name.toLowerCase().includes(lc) || lc.includes(p.name.toLowerCase())));
  if (match && match.imageUrl) imagenProductoUrl = match.imageUrl;
}
return [{ json: { response: responseText, imagenProductoUrl: imagenProductoUrl, phone: ctx.phone, tenantId: ctx.tenantId, instanceName: ctx.instanceName, evolutionApiUrl: ctx.evolutionApiUrl, evolutionApiKey: ctx.evolutionApiKey, intent: 'ventas', intent_handled: 'ventas', action_taken: 'imagen_analizada', metadata: { pushName: ctx.pushName, producto_identificado: productoCatalogo } } }];

const router = $('Recibir Datos del Router').first().json;
const pdfData = $('Obtener Catalogo PDF').first().json;
const businessName = router.businessName || 'nuestros productos';
return [{
  json: {
    evolutionUrl: router.evolutionApiUrl + '/message/sendMedia/' + router.instanceName,
    evolutionApiKey: router.evolutionApiKey,
    requestBody: {
      number: router.phone,
      mediatype: 'document',
      mimetype: 'application/pdf',
      caption: 'Catalogo de ' + businessName,
      media: pdfData.pdfUrl,
      fileName: pdfData.fileName || 'catalogo.pdf'
    },
    phone: router.phone,
    tenantId: router.tenantId,
    pushName: router.pushName,
    businessName: businessName
  }
}];

const ctx = $('Preparar Envio PDF').first().json;
return [{
  json: {
    response: 'Listo, ' + (ctx.pushName || 'estimado cliente') + '! Te acabo de enviar el catalogo de ' + (ctx.businessName || 'nuestra tienda') + ' en PDF.\n\nHay algun producto que te llame la atencion? Con gusto te ayudo con precios, disponibilidad o para coordinar tu pedido.',
    phone: ctx.phone,
    tenantId: ctx.tenantId,
    intent: 'ventas',
    intent_handled: 'ventas',
    action_taken: 'catalogo_pdf_enviado',
    metadata: { pushName: ctx.pushName }
  }
}];

const input = $('Recibir Datos del Router').first().json;
const prods = (input.catalog || []);
const catalogLines = prods.slice(0, 10).map(p => {
  let line = `• *${p.name}*`;
  if (p.price) line += ` — $${Number(p.price).toLocaleString('es-CO')}`;
  if (p.available === false) line += ' _(no disponible)_';
  return line;
}).join('\n');
return [{
  json: {
    response: `¡Hola ${input.pushName || 'estimado cliente'}! 🛍️ Por el momento no tenemos catálogo en PDF, pero aquí están nuestros productos:\n\n${catalogLines || 'Escríbenos qué buscas y te ayudamos con gusto.'}\n\n¿Cuál te interesa? 😊`,
    phone: input.phone,
    tenantId: input.tenantId,
    intent: 'ventas',
    intent_handled: 'ventas',
    action_taken: 'catalogo_texto_enviado',
    metadata: { pushName: input.pushName }
  }
}];

const input = $input.first().json;
return [{ json: {
  ...input,
  mediaBody: {
    number: String(input.phone),
    mediatype: 'image',
    mimetype: 'image/jpeg',
    caption: '',
    media: input.imagenProductoUrl,
    fileName: 'producto.jpg'
  },
  evolutionUrl: (input.evolutionApiUrl || '') + '/message/sendMedia/' + (input.instanceName || '')
} }];

const imageResult = $input.first().json;
const visionData = $('Formatear Respuesta Imagen').first().json;
return [{ json: { response: visionData.response, phone: visionData.phone, tenantId: visionData.tenantId, intent_handled: 'ventas', action_taken: 'imagen_con_producto', metadata: visionData.metadata } }];

const input = $input.first().json;
return [{ json: {
  ...input,
  mediaBody: {
    number: String(input.phone),
    mediatype: 'image',
    mimetype: 'image/jpeg',
    caption: '',
    media: input.imagenProductoUrl,
    fileName: 'producto.jpg'
  },
  evolutionUrl: (input.evolutionApiUrl || '') + '/message/sendMedia/' + (input.instanceName || '')
} }];

const imageResult = $input.first().json;
const ventasData = $('Evaluar Respuesta Ventas').first().json;
return [{ json: { response: ventasData.response, phone: ventasData.phone, tenantId: ventasData.tenantId, intent_handled: 'ventas', action_taken: 'ventas_con_imagen', metadata: ventasData.metadata } }];
